class Solution:
    def canMakeSubsequence(self, str1, str2):
        def bumped(c):
            return chr((ord(c) - ord('a') + 1) % 26 + ord('a'))
        n, m = len(str1), len(str2)
        dp = [[False] * (m + 1) for _ in range(n + 1)]
        for i in range(n + 1):
            dp[i][0] = True
        for i in range(1, n + 1):
            for j in range(1, m + 1):
                dp[i][j] = dp[i - 1][j]
                if not dp[i][j]:
                    c = str1[i - 1]
                    if c == str2[j - 1] or bumped(c) == str2[j - 1]:
                        dp[i][j] = dp[i - 1][j - 1]
        return dp[n][m]

