class Solution:
    def canMakeSubsequence(self, str1, str2):
        m = len(str2)
        j = 0
        for c in str1:
            if j == m:
                break
            bumped = chr((ord(c) - ord('a') + 1) % 26 + ord('a'))
            if c == str2[j] or bumped == str2[j]:
                j += 1
        return j == m

