var canMakeSubsequence = function(str1, str2) {
    const m = str2.length;
    let j = 0;
    for (let i = 0; i < str1.length && j < m; i++) {
        const code = str1.charCodeAt(i) - 97;
        const bumped = String.fromCharCode(((code + 1) % 26) + 97);
        if (str1[i] === str2[j] || bumped === str2[j]) {
            j++;
        }
    }
    return j === m;
};
